THE CLAIM:
{
 "title": "EU Cyber Resilience Act cuts networked PDU sales in Year 1",
 "narrative": "The model assumes the PDU clears the old CE and TUV compliance stack and can be quoted into 2026 tenders. But the Cyber Resilience Act adds new duties from 11 September 2026 and full conformity from 11 December 2027, and data-center buyers are already demanding CRA-readiness in 2026 bids. That pushes Year-1 share below the 1% pace the number assumes.",
 "mechanism": [
  {
   "step": "trigger",
   "text": "CRA duties start Sept 2026 and Dec 2027, inside the entry window",
   "refs": [
    "profile:Product",
    "profile:Stage",
    "ledger:serviceableFactor"
   ]
  },
  {
   "step": "propagation",
   "text": "Buyers add CRA-readiness clauses to 2026 bids for durable gear",
   "refs": [
    "digest:serviceable-benchmark#c4",
    "digest:serviceable-benchmark#c13",
    "ledger:serviceableFactor"
   ]
  },
  {
   "step": "propagation",
   "text": "Entrant lacks the certification, so it drops off shortlists",
   "refs": [
    "digest:refine-demand-discontinuity.prelet-pipeline-lockout#c0",
    "digest:refine-competitive-foreclosure.bundling-eliminates-bakeoffs-year1#c0",
    "ledger:obtainableFactor"
   ]
  },
  {
   "step": "model-impact",
   "text": "Reachable demand shrinks and Year-1 share falls below 1%",
   "refs": [
    "ledger:serviceableFactor",
    "ledger:obtainableFactor"
   ]
  }
 ],
 "falsifier": "Three 2026 data-center PDU bids with no CRA or SBOM requirement, plus confirmation networked PDUs stay in the CRA self-assessment class.",
 "category": "exogenous",
 "evidence": [
  {
   "title": "Cyber Resilience Act (CRA) — DG CONNECT webinar slides",
   "sourceType": "industry-report",
   "publisher": "ENISA / European Commission DG CONNECT",
   "date": null,
   "excerpt": "Entry into application: 11 December 2027 except for reporting obligations: 11 September 2026. In scope: 'products with digital elements'... network equipment... including their remote data processing solutions!",
   "url": "https://certification.enisa.europa.eu/document/download/9d04238b-7f18-4575-a7dd-638afc92e019_en?filename=Slides_CRA_EUCC_webinar_June_2025.pdf&prefLang=fr",
   "attached": true
  },
  {
   "title": "CRA Product Classes: Implementing Regulation 2025/2392 Technical Descriptions",
   "sourceType": "industry-report",
   "publisher": "Safeguard",
   "date": "2026-01-15",
   "excerpt": "The default tier — roughly 90 per cent of products — permits self-assessment under conformity assessment Module A... Commission Implementing Regulation (EU) 2025/2392, signed on 28 November 2025... fixes the technical descriptions of each category.",
   "url": "https://safeguard.sh/resources/blog/cra-implementing-regulation-2025-2392-product-classes",
   "attached": true
  },
  {
   "title": "Cyber Resilience Act 2026: A Compliance Guide for OEMs",
   "sourceType": "industry-report",
   "publisher": "ComponentSense",
   "date": "2026-06-16",
   "excerpt": "From 11th September 2026, electronics manufacturers selling into the EU will be facing a new legal obligation... If your product connects directly or indirectly to a network or device, it falls within scope.",
   "url": "https://www.componentsense.com/blog/cyber-resilience-act-2026-a-compliance-guide-for-oems",
   "attached": true
  }
 ]
}

THE LEDGER FACTS IT TARGETS (current values, derivations, bands):
[
 {
  "id": "serviceableFactor",
  "label": "Serviceable share of TAM",
  "kind": "assumption",
  "value": 0.55,
  "unit": "ratio",
  "confidence": "inferred",
  "maturity": "needs-source",
  "dimension": null,
  "dimensionValue": null,
  "sensitivityRange": {
   "low": 0.45,
   "high": 0.65
  },
  "funnelActive": true,
  "derivation": {
   "method": "Reachability assumption",
   "expression": "No public SAM/TAM benchmark for B2B hardware exists; EU cert stack (EN 50600, ecodesign 2019/424, CE/TÜV) justifies < 1.0 but doesn't quantify 0.55"
  },
  "provenance": {
   "rationale": "Assumption leaf — channel + regulatory reach; EU certification barriers documented qualitatively only.",
   "promotionPath": "Bottom-up channel-coverage model (named accounts × reachable share) → sourced serviceable %."
  },
  "evidence": [
   {
    "title": "EU ecodesign requirements for servers and data storage (2019/424)",
    "sourceType": "industry-report",
    "publisher": "EUR-Lex",
    "date": "2019",
    "excerpt": "EU ecodesign and certification requirements gate which demand is regulatory-clear for a new entrant — the qualitative basis of the serviceable haircut.",
    "attached": true
   }
  ]
 },
 {
  "id": "obtainableFactor",
  "label": "Year-1 obtainable share of SAM",
  "kind": "assumption",
  "value": 0.01,
  "unit": "ratio",
  "confidence": "inferred",
  "maturity": "triangulated",
  "dimension": null,
  "dimensionValue": null,
  "sensitivityRange": {
   "low": 0.005,
   "high": 0.03
  },
  "funnelActive": true,
  "derivation": {
   "method": "Benchmark anchoring",
   "expression": "Prospeo assigns 1% of SAM to YEAR 1 (3% and 5% are Years 2–3) — the prior 3% read the Year-2 figure as Year 1. Corrected to 1%; the Tractian comparable (first-year ~$1.2M against a multi-$B market) sits below 1%.",
   "crossCheck": "Early-procurement mechanism (DC electrical gear locked 12–24mo before fit-out) independently supports ≤2%; open 2026 EU rack-PDU tenders keep 2–3% inside the band."
  },
  "provenance": {
   "rationale": "Refinement cycle 1 caught the benchmark-period misread — the value now follows the source's own Year-1 figure, band 0.5–3%.",
   "promotionPath": "Replace with pipeline-based model once first CE deals close (win-rate × cycle time × capacity)."
  },
  "evidence": [
   {
    "title": "Addressable markets — SOM benchmarks",
    "sourceType": "analyst-estimate",
    "publisher": "Prospeo",
    "date": null,
    "excerpt": "SOM benchmarks that won't get you laughed out of the room: 1% of SAM in Year 1, 3% in Year 2, 5% in Year 3.",
    "attached": true
   },
   {
    "title": "Serviceable Obtainable Market (SOM) — early-stage ranges",
    "sourceType": "analyst-estimate",
    "publisher": "IdeaPlan",
    "date": "2024",
    "excerpt": "For early-stage companies, SOM is typically 1-5% of SAM. For growing companies with product-market fit, SOM can reach 10-20% of SAM.",
    "attached": true
   }
  ]
 }
]

Emit JSON: { resolution: "error"|"risk", settleTest, proposedCorrection: {nodeId, value, low, high, rationale} or null, researchQueries: [{query, kind}] ([] for risks) }
